          const f = String(filter.value).toLowerCase();
          if (filter.operator === 'ctns') return v.includes(f);
          if (filter.operator === 'eq')   return v === f;
          if (filter.operator === 'sw')   return v.startsWith(f);
          if (filter.operator === 'ew')   return v.endsWith(f);
